foreach ($img in $images) {
  $outPath = "public\timeline\" + $img.file
  if (Test-Path $outPath) {
    Write-Host "Already exists: $($img.file)"
  } else {
    try {
      Invoke-WebRequest -Uri $img.url -OutFile $outPath -UseBasicParsing
      Write-Host "Downloaded: $($img.file)"
    } catch {
      Write-Host "Failed: $($img.file) - $_"
    }
  }
}
Write-Host "Done!"
